import React, { useState } from "react";

// Trang Home (demo)
const HomePage = ({ input1, onChangeInput1 }) => {
  return (
    <div className="p-6">
      <h1 className="text-3xl font-bold mb-4">Trang chủ</h1>
      <input
        placeholder="Tìm kiếm trên Home"
        value={input1}
        onChange={(e) => onChangeInput1(e.target.value)}
        className="border rounded px-4 py-2 w-[400px]"
      />
      <p className="mt-4">Nội dung HomePage hiển thị ở đây...</p>
    </div>
  );
};

// Trang FriendList
const FriendList = () => {
  const friends = ["Nguyễn Văn A", "Nguyễn Văn B", "Nguyễn Văn C"];
  const suggestions = ["Trần Thị X", "Lê Văn Y", "Phạm Thị Z"];

  return (
    <div className="flex gap-6 p-6">
      {/* Danh sách bạn bè */}
      <div className="flex-1 flex flex-col gap-4">
        <h2 className="text-2xl font-bold mb-3">Danh sách bạn bè</h2>
        {friends.map((name, idx) => (
          <div
            key={idx}
            className="flex items-center gap-4 bg-[#A2D3FF] p-3 rounded-lg"
          >
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
              className="w-[90px] h-20 object-fill"
            />
            <span className="text-black text-2xl flex-1">{name}</span>
            <button className="bg-white px-3 py-1 rounded-lg">Delete</button>
            <button className="bg-[#F6FEFF] px-3 py-1 rounded-lg">Follow</button>
          </div>
        ))}
      </div>

      {/* Gợi ý kết bạn */}
      <div className="w-[300px] flex flex-col gap-3">
        <h2 className="text-2xl font-bold mb-3">Gợi ý kết bạn</h2>
        {suggestions.map((name, idx) => (
          <div
            key={idx}
            className="flex items-center gap-4 bg-[#F0F8FF] p-3 rounded-lg"
          >
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
              className="w-[60px] h-16 object-fill"
            />
            <span className="flex-1 text-black text-xl">{name}</span>
            <button className="bg-[#88BCF8] text-white px-3 py-1 rounded-lg">
              Thêm bạn
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

// App chính
export default function App() {
  const [currentPage, setCurrentPage] = useState("home");
  const [input1, onChangeInput1] = useState("");

  return (
    <div className="flex">
      {/* Sidebar */}
      <div className="flex flex-col items-center bg-[#88BCF8] w-[88px] py-[25px] px-[23px] gap-[30px]">
        <img
          src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/yrrmpwtt_expires_30_days.png"
          className="w-[42px] h-[42px] cursor-pointer"
          onClick={() => setCurrentPage("home")}
        />
        <img
          src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/31c1kzbw_expires_30_days.png"
          className="w-[42px] h-[37px] cursor-pointer"
          onClick={() => setCurrentPage("friends")}
        />
      </div>

      {/* Nội dung trang */}
      <div className="flex-1">
        {currentPage === "home" && (
          <HomePage input1={input1} onChangeInput1={onChangeInput1} />
        )}
        {currentPage === "friends" && <FriendList />}
      </div>
    </div>
  );
}
